/**
 * Extract final rationale from selected labels
 */
function extractFinalRationale(selectedLabels: SelectedLabel[]): string {
  if (selectedLabels.length === 0) {
    return 'No labels selected - classification uncertain';
  }

  const primary = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
  return primary.selectionRationale || `Selected ${primary.category} with confidence ${primary.confidence}`;
}

/**
 * Extract keywords array from candidate scores and selection summary
 */
function extractKeywords(result: ClassificationResult): string[] {
  const keywords: string[] = [];

  // Add selected categories as keywords
  result.selectedLabels.forEach((label: SelectedLabel) => {
    keywords.push(label.category);
    if (label.subtype) {
      keywords.push(label.subtype);
    }
  });

  // Add top candidate categories
  if (result.selectionSummary.topCategories) {
    result.selectionSummary.topCategories.forEach((cat: { category: string; score: number }) => {
      if (!keywords.includes(cat.category)) {
        keywords.push(cat.category);
      }
    });
  }

  return keywords;
}

/**
 * Build final features JSONB from classification result
 */
function buildFinalFeatures(result: ClassificationResult): object {
  return {
    selectionMethod: result.selectionSummary.selectionMethod,
    totalLabels: result.selectionSummary.totalLabels,
    confidenceRange: result.selectionSummary.confidenceRange,
    needsAi: result.selectionSummary.needsAi,
    candidateScores: result.candidateScores,
    processingDurationMs: result.processingDurationMs,
  };
}

/**
 * Insert classification_session record
 *
 * @param pool - PostgreSQL connection pool
 * @param messageId - Gmail message ID
 * @param result - Classification result
 * @param startedAt - Session start timestamp
 * @param completedAt - Session completion timestamp
 * @returns session_id from inserted record
 */
async function insertClassificationSession(
  pool: Pool,
