  min_delta_primary_secondary: number;
  allow_financial_actionable_copresence: boolean;
}

/**
 * Domain signal overrides for specific category behaviors
 */
export interface DomainOverrides {
  [category: string]: {
    hard_include: string[];
    hard_exclude: string[];
    strong_include: string[];
    strong_exclude: string[];
  };
}

/**
 * Domain resolution configuration
 */
export interface DomainResolution {
  mode: string; // "runtime_resolved"
  source: string; // "config/domain-sources.json"
  notes: string;
}

/**
 * Top-level category definition with subtypes and AI classification
 */
export interface TopLevelCategory {
  description: string;
  subtypes: Record<string, SubtypeDefinition>;
  ai_final_classification: {
    category_description: string;
    decision_criteria: string[];
    exclusion_criteria?: string[];
  };
}

/**
 * Subtype definition with rule-based classification
 */
export interface SubtypeDefinition {
  description: string;
  rule_based_classification?: {
    high_confidence?: RulePattern[];
    medium_confidence?: RulePattern[];
    low_confidence?: RulePattern[];
  };
  derived?: boolean;
  derivation_logic?: string;
}

/**
 * Rule pattern for rule-based classification
 */
export interface RulePattern {
  field: string; // "subject", "body", "from.address", etc.
  operation: string; // "contains_any", "starts_with", "ends_with", "regex_any", "exists"
  values?: string[];
  weight: number;
}

/**
 * Attribute system configuration
 */
export interface AttributeSystem {
  schema: Record<string, AttributeSchema>;
  detectors: AttributeDetector[];
  derived: Record<string, DerivedAttribute>;
  attribute_bonus_map: Record<string, Record<string, number>>;
}

export interface AttributeSchema {
  type: string; // "enum", "boolean"
  values?: string[]; // For enum types
  description: string;
}

export interface AttributeDetector {
  attribute: string;
  field: string;
  operation: string;
  values: string[];
}

export interface DerivedAttribute {
  logic: string;
  notes: string;
}

/**
 * Attribute relevance matrix implementing roles from SCORING_LOGIC.md
 */
export interface AttributeRelevanceMatrix {
  _roles_legend: {
    CORE: string;
    PRIMARY_BOOST: string;
    SECONDARY_BOOST: string;
    DISAMBIGUATOR: string;
    FILTER: string;
    STRUCTURAL: string;
    DERIVED_LINK: string;
    NEUTRAL: string;
  };
  [category: string]:
    | {
        category_roles: Record<string, AttributeRole>;
        subtypes?: Record<
          string,
          {
            roles: Record<string, AttributeRole>;
          }
        >;
      }
    | {
        CORE: string;
        PRIMARY_BOOST: string;
        SECONDARY_BOOST: string;
        DISAMBIGUATOR: string;
        FILTER: string;
        STRUCTURAL: string;
        DERIVED_LINK: string;
        NEUTRAL: string;
      }; // For _roles_legend
}

export type AttributeRole =
  | 'CORE'
  | 'PRIMARY_BOOST'
  | 'SECONDARY_BOOST'
  | 'DISAMBIGUATOR'
  | 'FILTER'
  | 'STRUCTURAL'
  | 'DERIVED_LINK'
  | 'NEUTRAL';

/**
 * AI prompt system configuration
 */
export interface AIPromptSystem {
  feature_extraction: {
    system_prompt: string[];
    user_prompt: string[];
  };
  final_classification: {
    system_prompt: string[];
    user_prompt: string[];
  };
}

/**
 * JSON schema for feature extraction
 */
export interface JSONSchema {
  type: string;
  properties: Record<string, JSONSchemaProperty>;
  required: string[];
}

export interface JSONSchemaProperty {
  type: string;
  description?: string;
  enum?: string[];
  items?: JSONSchemaProperty;
  properties?: Record<string, JSONSchemaProperty>;
  required?: string[];
}

/**
 * Pre-compiled rule for performance optimization
 */
export interface CompiledRule {
  category: string;
  subtype: string;
  tier: string;
  pattern: RegExp;
  weight: number;
}

/**
 * Pre-computed attribute influence matrix for performance
 */
export interface AttributeInfluenceMatrix {
  [category: string]: {
    [attribute: string]: {
      role: AttributeRole;
      bonus: number;
      cap: number;
    };
  };
}

/**
 * Zod schema for runtime validation of CategoryConfiguration
 * This implements all tuning parameters from SCORING_LOGIC.md
 */
export const CategoryConfigurationSchema = z.object({
  version: z.string(),
  lastModified: z.date(),
  hash: z.string(),

  processing_config: z.object({
    version: z.number(),
    taxonomy_notes: z.string(),

    settings: z.object({
      initialization: z.object({
        apply_hard_assertions: z.boolean(),
        seed_category_scores: z.boolean(),
      }),
      rule_scoring: z.object({
        use_lexical_patterns: z.boolean(),
        apply_subtype_rules: z.boolean(),
        bounded_aggregation: z.boolean(),
      }),
      attribute_processing: z.object({
        detect_self_sent: z.boolean(),
        resolve_domains: z.boolean(),
        derive_context_flags: z.boolean(),
      }),
      attribute_influence: z.object({
        apply_bonuses: z.boolean(),
        apply_penalties: z.boolean(),
        enforce_caps: z.boolean(),
      }),
      disambiguation: z.object({
        pairwise_adjustments: z.boolean(),
        confidence_gap_threshold: z.number().min(0).max(1),
      }),
      multi_label_selection: z.object({
        max_labels: z.number().int().positive(),
        min_secondary_confidence: z.number().min(0).max(1),
        allowed_combinations: z.array(z.string()),
      }),
      ai_routing: z.object({
        high_confidence_threshold: z.number().min(0).max(1),
        ai_required_threshold: z.number().min(0).max(1),
        skip_ai_conditions: z.array(z.string()),
      }),
    }),

    category_signals: z.record(
      z.object({
        hard_assertions: z.object({
          from_domains_ref: z
            .object({
              source_group: z.string(),
              confidence: z.string(),
            })
            .optional(),
          subject_prefixes: z.array(z.string()).optional(),
          from_addresses: z.array(z.string()).optional(),
        }),
        strong_indicators: z.object({
          from_domains_ref: z
            .object({
              source_group: z.string(),
              confidence: z.string(),
            })
            .optional(),
          subject_contains: z.array(z.string()).optional(),
          body_contains: z.array(z.string()).optional(),
        }),
        disambiguators: z
          .object({
            boost_if_present_attributes: z.array(z.string()).optional(),
            suppress_if_body_contains: z.array(z.string()).optional(),
            boost_if_absent_categories: z.array(z.string()).optional(),
          })
          .optional(),
      })
    ),

    confidence_thresholds: z.object({
      high_confidence: z.number().min(0).max(1),
      medium_confidence: z.number().min(0).max(1),
      low_confidence: z.number().min(0).max(1),
      ai_classification_required: z.number().min(0).max(1),
      manual_review_required: z.number().min(0).max(1),
      secondary_label_min_gap: z.number().min(0).max(1),
    }),

    multi_label_policy: z.object({
      max_top_level_labels: z.number().int().positive(),
      min_confidence_for_additional: z.number().min(0).max(1),
      min_delta_primary_secondary: z.number().min(0).max(1),
      allow_financial_actionable_copresence: z.boolean(),
    }),

    // Additional configuration sections...
    domain_signal_overrides: z.record(
      z.object({
        hard_include: z.array(z.string()),
        hard_exclude: z.array(z.string()),
        strong_include: z.array(z.string()),
        strong_exclude: z.array(z.string()),
      })
    ),

    domain_signal_resolution: z.object({
      mode: z.string(),
      source: z.string(),
      notes: z.string(),
    }),

    top_level_categories: z.record(
      z.object({
        description: z.string(),
        subtypes: z.record(
          z.object({
            description: z.string(),
            rule_based_classification: z
              .object({
                high_confidence: z
                  .array(
                    z.object({
                      field: z.string(),
                      operation: z.string(),
                      values: z.array(z.string()).optional(),
                      weight: z.number(),
                    })
                  )
                  .optional(),
                medium_confidence: z
                  .array(
                    z.object({
                      field: z.string(),
                      operation: z.string(),
                      values: z.array(z.string()).optional(),
                      weight: z.number(),
                    })
                  )
                  .optional(),
                low_confidence: z
                  .array(
                    z.object({
                      field: z.string(),
                      operation: z.string(),
                      values: z.array(z.string()).optional(),
                      weight: z.number(),
                    })
                  )
                  .optional(),
              })
              .optional(),
            derived: z.boolean().optional(),
            derivation_logic: z.string().optional(),
          })
        ),
        ai_final_classification: z.object({
          category_description: z.string(),
          decision_criteria: z.array(z.string()),
          exclusion_criteria: z.array(z.string()).optional(),
        }),
      })
    ),

    attributes: z.object({
      schema: z.record(
        z.object({
          type: z.string(),
          values: z.array(z.string()).optional(),
          description: z.string(),
        })
      ),
      detectors: z.array(
        z.object({
          attribute: z.string(),
          field: z.string(),
          operation: z.string(),
          values: z.array(z.string()),
        })
      ),
      derived: z.record(
        z.object({
          logic: z.string(),
          notes: z.string(),
        })
      ),
      attribute_bonus_map: z.record(z.record(z.number())),
    }),

    attribute_relevance: z.record(z.any()), // Complex nested structure, validated separately

    ai_prompts: z.object({
      feature_extraction: z.object({
        system_prompt: z.array(z.string()),
        user_prompt: z.array(z.string()),
      }),
      final_classification: z.object({
        system_prompt: z.array(z.string()),
        user_prompt: z.array(z.string()),
      }),
    }),

    feature_extraction_schema: z.object({
      type: z.string(),
      properties: z.record(z.any()),
      required: z.array(z.string()),
    }),
  }),

  schemaVersion: z.string(),
  validationPassed: z.boolean(),
  validationErrors: z.array(z.string()),
  compiledRules: z.array(z.any()), // Compiled at runtime
  attributeMatrix: z.record(z.any()), // Pre-computed at runtime
});

export type ValidatedCategoryConfiguration = z.infer<typeof CategoryConfigurationSchema>;

