const fs = require('fs');
const path = require('path');

const filePath = path.join(process.cwd(), 'packages/classification-engine/src/stages/disambiguation.ts');
let content = fs.readFileSync(filePath, 'utf-8');

// All remaining transformations for disambiguation.ts
const transformations = {
  // DisambiguationResult interface
  'competing_categories': 'competingCategories',
  'adjustments_applied': 'adjustmentsApplied',
  'original_scores': 'originalScores',
  'updated_scores': 'updatedScores',
  'score_deltas': 'scoreDeltas',
  'processing_duration_ms': 'processingDurationMs',
  'configuration_references': 'configurationReferences',
  'disambiguation_settings_path': 'disambiguationSettingsPath',

  // CompetingCategoryPair interface
  'score_gap': 'scoreGap',
  'requires_disambiguation': 'requiresDisambiguation',
  'subtype_competition': 'subtypeCompetition',

  // DisambiguationAdjustment interface
  'adjustment_amount': 'adjustmentAmount',
  'adjustment_reason': 'adjustmentReason',
  'confidence_factor': 'confidenceFactor',
  'decay_applied': 'decayApplied',
  'decay_factor': 'decayFactor'
};

let count = 0;
for (const [snake, camel] of Object.entries(transformations)) {
  // Match property declarations (with optional ?)
  const regex = new RegExp(`\\b${snake}\\s*\\??\\s*:`, 'g');
  const matches = content.match(regex);
  if (matches) {
    content = content.replace(regex, (match) => {
      count++;
      return match.replace(snake, camel);
    });
    console.log(`✓ ${snake} → ${camel} (${matches.length} occurrences)`);
  }
}

fs.writeFileSync(filePath, content, 'utf-8');
console.log(`\n✅ Fixed ${count} properties in disambiguation.ts`);

