function calculateDisambiguationAdjustments(
  competingCategories: CompetingCategoryPair[],
  context: AttributeContext,
  config: CategoryConfiguration,
  disambiguationConfig: DisambiguationConfig
): DisambiguationAdjustment[] {
  const adjustments: DisambiguationAdjustment[] = [];
  const categoryAdjustmentCounts: Record<string, number> = {};

  // Get all categories involved in competition
  const involvedCategories = new Set<string>();
  for (const pair of competingCategories) {
    involvedCategories.add(pair.category1);
    involvedCategories.add(pair.category2);
  }

  // Find DISAMBIGUATOR attributes for involved categories
  for (const [attributeName, metadata] of Object.entries(context.detectionMetadata)) {
    for (const categoryName of Array.from(involvedCategories)) {
      const categoryKey = getCategoryKey(categoryName);
      const subtypeKey = getSubtypeKey(categoryName);

      const attributeRole = getAttributeRole(attributeName, categoryKey, subtypeKey, config);

