const fs = require('fs');
const path = require('path');

// Load transformation mapping
const mapping = JSON.parse(fs.readFileSync('/tmp/camelCase-transformation-map.json', 'utf-8'));

// Get all test files
const testDir = path.join(process.cwd(), 'packages/classification-engine/tests');
const testFiles = [
  'api/batch-classification.test.ts',
  'api/config-validation.test.ts',
  'api/single-classification.test.ts',
  'unit/template-utils.test.ts',
  'unit/ai-feature-extraction.test.ts',
  'unit/ai-classification.test.ts',
  'unit/final-decision.test.ts',
  'unit/audit-trail.test.ts',
  'unit/validation.test.ts',
  'unit/classification-pipeline.test.ts',
  'unit/category-utils.test.ts',
  'unit/email-utils.test.ts',
  'unit/performance-tracking.test.ts',
  'unit/initialization.test.ts',
  'unit/strong-indicators.test.ts',
  'unit/hard-assertions.test.ts',
  'unit/attribute-influence.test.ts',
  'unit/disambiguation.test.ts',
  'unit/ai-routing.test.ts',
  'unit/multi-label-selection.test.ts',
  'unit/attribute-detection.test.ts',
  'unit/rule-scoring.test.ts',
];

// Sort keys by length (longest first) to avoid partial replacements
const sortedKeys = Object.keys(mapping).sort((a, b) => b.length - a.length);

let totalTransforms = 0;
let filesModified = 0;

for (const file of testFiles) {
  const filePath = path.join(testDir, file);

  if (!fs.existsSync(filePath)) {
    console.log(`⚠️  Skipping ${file} (not found)`);
    continue;
  }

  let content = fs.readFileSync(filePath, 'utf-8');
  let fileTransforms = 0;

  sortedKeys.forEach(snakeCase => {
    const camelCase = mapping[snakeCase];

    // Match property declarations with values (snake_case: value)
    const propRegex = new RegExp(`\\b${snakeCase}\\s*:\\s*`, 'g');
    const matches = content.match(propRegex);

    if (matches) {
      content = content.replace(propRegex, `${camelCase}: `);
      fileTransforms += matches.length;
      totalTransforms += matches.length;
    }
  });

  if (fileTransforms > 0) {
    fs.writeFileSync(filePath, content, 'utf-8');
    filesModified++;
    console.log(`✓ ${file} (${fileTransforms} transformations)`);
  }
}

console.log(`\n✅ Modified ${filesModified} test files with ${totalTransforms} total transformations`);

