const fs = require('fs');
const path = require('path');

const filePath = 'packages/classification-engine/tests/unit/disambiguation.test.ts';
let content = fs.readFileSync(filePath, 'utf-8');

// Fix property accesses (after dots and exclamation marks)
const replacements = {
  '\\.processing_config!': '.processingConfig!',
  '\\.processing_config\\.': '.processingConfig.',
  '\\.attribute_relevance\\.': '.attributeRelevance.',
  '\\.enable_subtype_disambiguation': '.enableSubtypeDisambiguation',
  '\\.confidence_gap_threshold': '.confidenceGapThreshold',
  '\\.hard_assertions': '.hardAssertions',
  '\\.strong_indicators': '.strongIndicators',
  '_roles_legend': 'RolesLegend',  // This should already be RolesLegend
};

let count = 0;
for (const [pattern, replacement] of Object.entries(replacements)) {
  const regex = new RegExp(pattern, 'g');
  const matches = content.match(regex);
  if (matches) {
    content = content.replace(regex, replacement);
    count += matches.length;
    console.log(`✓ ${pattern} → ${replacement} (${matches.length} occurrences)`);
  }
}

fs.writeFileSync(filePath, content, 'utf-8');
console.log(`\n✅ Fixed ${count} property accesses in disambiguation.test.ts`);

