/**
 * Unit tests for T033: Disambiguation Stage
 *
 * TDD Approach: These tests MUST FAIL before implementation
 *
 * Tests validate:
 * - Pairwise category conflicts and resolution
 * - Confidence gap thresholds
 * - Score adjustment scenarios
 * - Configuration validation
 */

import { describe, test, expect, beforeEach } from '@jest/globals';
import { EmailMessage } from '../../src/types/email-message';
import { AttributeContext } from '../../src/types/attribute-context';
import { CategoryConfiguration } from '../../src/types/category-configuration';
import { executeDisambiguation } from '../../src/stages/disambiguation';
import { createClassificationSession, createClassificationResult } from '../../src/utils/initialization';

describe('Disambiguation Stage (T033)', () => {
  let mockEmail: EmailMessage;
  let mockContext: AttributeContext;
  let mockConfig: CategoryConfiguration;

  beforeEach(() => {
    // Setup test email
    mockEmail = {
      id: 'test-email-123',
      threadId: 'thread-456',
      gmailLabels: ['INBOX'],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'test@example.com' },
          { name: 'Subject', value: 'Test Email' },
        ],
        body: { data: 'VGVzdCBlbWFpbCBib2R5' },
      },
      bodyPlain: 'Test email body',
      bodyHtml: '<p>Test email body</p>',
      subject: 'Test Email',
      from: {
        email: 'test@example.com',
        raw: 'test@example.com',
      },
      to: [
        {
          email: 'recipient@example.com',
          raw: 'recipient@example.com',
        },
      ],
      date: new Date('2024-01-01T10:00:00Z'),
      snippet: 'Test email body',
      isProcessed: false,
      processingPriority: 1,
    };

    // Setup attribute context
    mockContext = {
      emailId: 'test-email-123',
      urgency: 'medium',
      domains: ['financial.com'],
      structuralPatterns: ['invoice_pattern'],
      temporalSignals: ['end_of_month'],
      detectionMetadata: {},
      influenceApplications: [],
      derivedAttributes: {},
      attributeRelationships: [],
    };

    // Setup category configuration with disambiguation settings
    mockConfig = {
      version: '1.0',
      lastModified: new Date('2024-01-01'),
      hash: 'test-hash',
      schemaVersion: '1.0',
      validationPassed: true,
      validationErrors: [],
      compiledRules: [],
      attributeMatrix: {},
      processingConfig: {
        version: 1,
        taxonomyNotes: 'Test configuration',
        categorySignals: {},
        settings: {
          initialization: {
            applyHardAssertions: true,
            seedCategoryScores: true,
          },
          ruleScoring: {
            useLexicalPatterns: true,
            applySubtypeRules: true,
            boundedAggregation: true,
          },
          attributeProcessing: {
            detectSelfSent: true,
            resolveDomains: true,
            deriveContextFlags: true,
          },
          attributeInfluence: {
            applyBonuses: true,
            applyPenalties: true,
            enforceCaps: true,
          },
          disambiguation: {
            pairwiseAdjustments: true,
            confidenceGapThreshold: 0.15, // 15% gap required for clear winner
            max_adjustments_per_email: 5,
            adjustment_decay_factor: 0.8,
            enable_subtype_disambiguation: true,
          },
          multiLabelSelection: {
            maxLabels: 3,
            minSecondaryConfidence: 0.6,
            allowedCombinations: [],
          },
          aiRouting: {
            highConfidenceThreshold: 0.8,
            aiRequiredThreshold: 0.4,
            skipAiConditions: [],
          },
        },
        confidence_thresholds: {
          highConfidence: 0.8,
          mediumConfidence: 0.6,
          lowConfidence: 0.2,
          ai_classification_required: 0.4,
          manual_review_required: 0.1,
          secondary_label_min_gap: 0.15,
        },
        multiLabelPolicy: {
          maxTopLevelLabels: 3,
          minConfidenceForAdditional: 0.3,
          minDeltaPrimarySecondary: 0.15,
          allowFinancialActionableCopresence: false,
        },
        attributeRelevance: {
          RolesLegend: {
            CORE: 'Essential attributes that define the category',
            PRIMARY_BOOST: 'Strong positive indicators for the category',
            SECONDARY_BOOST: 'Moderate positive indicators',
            DISAMBIGUATOR: 'Helps choose between similar categories',
            FILTER: 'Rules out inappropriate categories',
            STRUCTURAL: 'Email structure and format indicators',
            DERIVED_LINK: 'Links to derived attribute calculations',
            NEUTRAL: 'No impact on category scoring',
          },
        },
        aiPrompts: {
          featureExtraction: {
            systemPrompt: [],
            userPrompt: [],
          },
          finalClassification: {
            systemPrompt: [],
            userPrompt: [],
          },
        },
        domainSignalOverrides: {},
        domainSignalResolution: {
          mode: 'runtime_resolved',
          source: 'config/domain-sources.json',
          notes: 'Test configuration',
        },
        topLevelCategories: {
          FINANCIAL: {
            description: 'Financial category',
            subtypes: {
              BILLING: {
                description: 'Billing subtype',
                ruleBasedClassification: {
                  highConfidence: [],
                  mediumConfidence: [],
                  lowConfidence: [],
                },
              },
              INSURANCE: {
                description: 'Insurance subtype',
                ruleBasedClassification: {
                  highConfidence: [],
                  mediumConfidence: [],
                  lowConfidence: [],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Financial emails',
              decisionCriteria: [],
            },
          },
        },
        attributes: {
          schema: {},
          detectors: [],
          derived: {},
          attributeBonusMap: {},
        },
        featureExtractionSchema: {
          type: 'object',
          properties: {},
          required: [],
        },
      },
    };
  });

  // Helper to set up test with initial scores
  function setupTest(categoryScores: Record<string, number> = {}) {
    const session = createClassificationSession(mockConfig.processingConfig!, 'sequential', 1);
    const result = createClassificationResult('test-email-123', session.id, 0);

    // Initialize score breakdown for test categories
    for (const [category, score] of Object.entries(categoryScores)) {
      result.scoreBreakdown.categoryScores[category] = {
        baseScore: score,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: score,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };
    }

    return { session, result };
  }

  describe('Confidence Gap Analysis', () => {
    test('should detect competing categories within threshold', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11, // Gap of 1 < threshold for disambiguation
        WORK: 6,
      });

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.disambiguationApplied).toBeDefined();
      expect(result.explainabilityTrace.disambiguation).toBeDefined();
    });

    test('should skip disambiguation for clear winners', () => {
      const { session, result } = setupTest({
        FINANCIAL: 17,
        PERSONAL: 6, // Clear gap
        WORK: 2,
      });

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.disambiguationApplied).toHaveLength(0);
    });

    test('should handle multiple competing pairs', () => {
      const { session, result } = setupTest({
        FINANCIAL: 13,
        PERSONAL: 12, // Gap: 1
        WORK: 12, // Gap with PERSONAL: 0
      });

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Should identify multiple competing pairs
      expect(result.scoreBreakdown.disambiguationApplied.length).toBeGreaterThanOrEqual(1);
    });
  });

  describe('Disambiguation Adjustments', () => {
    test('should apply DISAMBIGUATOR attribute bonuses', () => {
      const { session, result } = setupTest({
        FINANCIAL: 0.72,
        PERSONAL: 0.68, // Gap of 0.04 < 0.15 threshold - triggers disambiguation
      });

      // Setup DISAMBIGUATOR attributes in context
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.8,
        evidence: 'Urgent keywords found',
      };

      // Configure DISAMBIGUATOR role
      mockConfig.processingConfig!.attributeRelevance.FINANCIAL = {
        categoryRoles: {
          urgent_indicator: 'DISAMBIGUATOR',
        },
      };

      // Pass context through result
      result.attributeContext = mockContext;

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Expect disambiguation was applied (format is different from raw adjustments)
      expect(result.scoreBreakdown.disambiguationApplied.length).toBeGreaterThanOrEqual(1);
      expect(result.scoreBreakdown.disambiguationApplied[0].categories).toContain('FINANCIAL');
      expect(result.scoreBreakdown.disambiguationApplied[0].categories).toContain('PERSONAL');
    });

    test('should apply score adjustments based on attribute confidence', () => {
      const { session, result } = setupTest({
        FINANCIAL: 0.7,
        WORK: 0.68, // Gap of 0.02 < 0.15 threshold - triggers disambiguation
      });

      // High confidence DISAMBIGUATOR attribute
      mockContext.detectionMetadata.priority_flag = {
        detectedAt: new Date(),
        detectionMethod: 'header_analysis',
        confidence: 0.95,
        evidence: 'High priority header found',
      };

      mockConfig.processingConfig!.attributeRelevance.WORK = {
        categoryRoles: {
          priority_flag: 'DISAMBIGUATOR',
        },
      };

      // Pass context through result
      result.attributeContext = mockContext;

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Expect disambiguation was applied to WORK and FINANCIAL pair
      expect(result.scoreBreakdown.disambiguationApplied.length).toBeGreaterThanOrEqual(1);
      const adjustment = result.scoreBreakdown.disambiguationApplied.find(
        (adj) => adj.categories.includes('WORK') && adj.categories.includes('FINANCIAL')
      );
      expect(adjustment).toBeDefined();
      expect(result.scoreBreakdown.categoryScores['WORK'].finalScore).toBeGreaterThan(0.68);
    });

    test('should enforce adjustment limits per email', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        WORK: 11,
        PERSONAL: 10,
      });

      // Setup multiple DISAMBIGUATOR attributes
      mockContext.detectionMetadata = {
        urgent_indicator: {
          detectedAt: new Date(),
          detectionMethod: 'keyword_analysis',
          confidence: 0.8,
          evidence: 'Urgent keywords',
        },
        priority_flag: {
          detectedAt: new Date(),
          detectionMethod: 'header_analysis',
          confidence: 0.9,
          evidence: 'Priority header',
        },
        deadline_mention: {
          detectedAt: new Date(),
          detectionMethod: 'text_analysis',
          confidence: 0.7,
          evidence: 'Deadline mentioned',
        },
        formal_language: {
          detectedAt: new Date(),
          detectionMethod: 'nlp_analysis',
          confidence: 0.6,
          evidence: 'Formal language detected',
        },
        business_hours: {
          detectedAt: new Date(),
          detectionMethod: 'temporal_analysis',
          confidence: 0.8,
          evidence: 'Sent during business hours',
        },
        personal_tone: {
          detectedAt: new Date(),
          detectionMethod: 'sentiment_analysis',
          confidence: 0.7,
          evidence: 'Personal tone detected',
        },
      };

      // Configure all as DISAMBIGUATOR attributes for different categories
      mockConfig.processingConfig!.attribute_relevance = {
        RolesLegend: mockConfig.processingConfig!.attributeRelevance.RolesLegend,
        FINANCIAL: {
          categoryRoles: {
            urgent_indicator: 'DISAMBIGUATOR',
            deadline_mention: 'DISAMBIGUATOR',
          },
        },
        WORK: {
          categoryRoles: {
            priority_flag: 'DISAMBIGUATOR',
            formal_language: 'DISAMBIGUATOR',
            business_hours: 'DISAMBIGUATOR',
          },
        },
        PERSONAL: {
          categoryRoles: {
            personal_tone: 'DISAMBIGUATOR',
          },
        },
      };

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Should respect max_adjustments_per_email limit (5)
      expect(result.scoreBreakdown.disambiguationApplied.length).toBeLessThanOrEqual(5);
    });

    test('should apply decay factor to subsequent adjustments', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      // Setup multiple DISAMBIGUATOR attributes for same category
      mockContext.detectionMetadata = {
        urgent_indicator: {
          detectedAt: new Date(),
          detectionMethod: 'keyword_analysis',
          confidence: 0.8,
          evidence: 'Urgent keywords',
        },
        deadline_mention: {
          detectedAt: new Date(),
          detectionMethod: 'text_analysis',
          confidence: 0.8,
          evidence: 'Deadline mentioned',
        },
        priority_flag: {
          detectedAt: new Date(),
          detectionMethod: 'header_analysis',
          confidence: 0.8,
          evidence: 'Priority header',
        },
      };

      mockConfig.processingConfig!.attributeRelevance.FINANCIAL = {
        categoryRoles: {
          urgent_indicator: 'DISAMBIGUATOR',
          deadline_mention: 'DISAMBIGUATOR',
          priority_flag: 'DISAMBIGUATOR',
        },
      };

      executeDisambiguation(mockEmail, session, result, mockConfig);

      const financialAdjustments = result.scoreBreakdown.disambiguationApplied.filter((adj) =>
        adj.categories.includes('FINANCIAL')
      );

      if (financialAdjustments.length >= 2) {
        // Verify decay factor is being applied
        expect(financialAdjustments.length).toBeGreaterThanOrEqual(2);
      }
    });
  });

  describe('Subtype Disambiguation', () => {
    test('should disambiguate between subtypes within same category', () => {
      const { session, result } = setupTest({
        'FINANCIAL.BILLING': 12,
        'FINANCIAL.INSURANCE': 11, // Close subtype scores
      });

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.disambiguationApplied).toBeDefined();
    });

    test('should respect subtype disambiguation configuration', () => {
      const { session, result } = setupTest({
        'FINANCIAL.BILLING': 12,
        'FINANCIAL.INSURANCE': 11,
      });

      // Disable subtype disambiguation
      mockConfig.processingConfig!.settings.disambiguation!.enableSubtypeDisambiguation = false;

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Should skip subtype disambiguation
      expect(result.explainabilityTrace.disambiguation).toBeDefined();
    });
  });

  describe('Score Updates', () => {
    test('should update candidate scores after adjustments', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.8,
        evidence: 'Urgent keywords found',
      };

      mockConfig.processingConfig!.attributeRelevance.FINANCIAL = {
        categoryRoles: {
          urgent_indicator: 'DISAMBIGUATOR',
        },
      };

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Scores should be updated
      expect(result.scoreBreakdown.categoryScores.FINANCIAL.finalScore).toBeGreaterThanOrEqual(12);
      expect(result.scoreBreakdown.categoryScores.PERSONAL.finalScore).toBe(11); // Unchanged
    });

    test('should preserve original scores in metadata', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      const originalFinancialScore = result.scoreBreakdown.categoryScores.FINANCIAL.finalScore;

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.disambiguation).toBeDefined();
      expect(originalFinancialScore).toBe(12);
    });

    test('should track score deltas', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.8,
        evidence: 'Urgent keywords found',
      };

      mockConfig.processingConfig!.attributeRelevance.FINANCIAL = {
        categoryRoles: {
          urgent_indicator: 'DISAMBIGUATOR',
        },
      };

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.disambiguationApplied).toBeDefined();
    });
  });

  describe('Performance and Processing Metadata', () => {
    test('should track processing duration', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.stageTimings.disambiguation).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.stageTimings.disambiguation).toBeLessThan(1000); // Should be fast
    });

    test('should track configuration references', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.configurationRefs.disambiguation).toBe(
        'processing_config.settings.disambiguation'
      );
    });

    test('should preserve existing context data', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      const originalContext = { ...mockContext };

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Original context should be preserved
      expect(mockContext.emailId).toBe(originalContext.emailId);
      expect(mockContext.detectionMetadata).toEqual(originalContext.detectionMetadata);
    });
  });

  describe('Error Handling and Edge Cases', () => {
    test('should handle missing disambiguation configuration', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      // Remove disambiguation configuration
      delete mockConfig.processingConfig!.settings.disambiguation;

      expect(() => executeDisambiguation(mockEmail, session, result, mockConfig)).toThrow(
        'Disambiguation configuration not found'
      );
    });

    test('should handle missing candidate scores', () => {
      const { session, result } = setupTest({});

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.disambiguationApplied).toHaveLength(0);
    });

    test('should handle empty candidate scores', () => {
      const { session, result } = setupTest({});

      executeDisambiguation(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.disambiguationApplied).toHaveLength(0);
    });

    test('should handle single category score', () => {
      const { session, result } = setupTest({
        FINANCIAL: 17,
      });

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // No disambiguation needed for single category
      expect(result.scoreBreakdown.disambiguationApplied).toHaveLength(0);
    });

    test('should validate confidence gap threshold', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      // Invalid threshold
      mockConfig.processingConfig!.settings.disambiguation!.confidenceGapThreshold = -0.1;

      expect(() => executeDisambiguation(mockEmail, session, result, mockConfig)).toThrow(
        'Invalid confidence threshold'
      );
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should work with attribute influence results', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'keyword_analysis',
        confidence: 0.8,
        evidence: 'Urgent keywords found',
      };

      // Configure DISAMBIGUATOR role for the attribute
      mockConfig.processingConfig!.attributeRelevance.FINANCIAL = {
        categoryRoles: {
          urgent_indicator: 'DISAMBIGUATOR',
        },
      };

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Should use previous influence applications in disambiguation
      expect(result.scoreBreakdown.disambiguationApplied.length).toBeGreaterThanOrEqual(0);
    });

    test('should preserve stage chain data', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

      // Track that previous stages have run
      result.explainabilityTrace.stageTimings.hardAssertions = 10;
      result.explainabilityTrace.stageTimings.strongIndicators = 15;

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Should preserve previous stage data
      expect(result.explainabilityTrace.stageTimings.hardAssertions).toBe(10);
      expect(result.explainabilityTrace.stageTimings.strongIndicators).toBe(15);
      expect(result.explainabilityTrace.stageTimings.disambiguation).toBeGreaterThanOrEqual(0);
    });
  });
});

