const fs = require('fs');
const path = require('path');
const glob = require('glob');

const testDir = 'packages/classification-engine/tests';
const testFiles = glob.sync(`${testDir}/**/*.test.ts`);

const replacements = {
  // Type narrowing checks
  "'category_roles' in": "'categoryRoles' in",
  "'processing_config'": "'processingConfig'",
  "'attribute_relevance'": "'attributeRelevance'",
  "'confidence_thresholds'": "'confidenceThresholds'",
  "'category_signals'": "'categorySignals'",

  // Property accesses
  '\\.processing_config\\.': '.processingConfig.',
  '\\.processing_config!': '.processingConfig!',
  '\\.attribute_relevance\\.': '.attributeRelevance.',
  '\\.category_roles\\.': '.categoryRoles.',
  '\\.confidence_thresholds\\.': '.confidenceThresholds.',
  '\\.category_signals\\.': '.categorySignals.',

  // Object literal properties (with colon)
  'secondary_label_min_gap:': 'secondaryLabelMinGap:',
  'processing_config:': 'processingConfig:',
};

let totalCount = 0;
let filesModified = 0;

for (const file of testFiles) {
  let content = fs.readFileSync(file, 'utf-8');
  let fileCount = 0;

  for (const [pattern, replacement] of Object.entries(replacements)) {
    const regex = new RegExp(pattern.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');
    const matches = content.match(regex);

    if (matches) {
      content = content.replace(regex, replacement);
      fileCount += matches.length;
      totalCount += matches.length;
    }
  }

  if (fileCount > 0) {
    fs.writeFileSync(file, content, 'utf-8');
    filesModified++;
    const relativePath = file.replace('packages/classification-engine/tests/', '');
    console.log(`✓ ${relativePath} (${fileCount} fixes)`);
  }
}

console.log(`\n✅ Fixed ${totalCount} property accesses in ${filesModified} test files`);

