// Load transformation mapping
const mapping = JSON.parse(fs.readFileSync('/tmp/camelCase-transformation-map.json', 'utf-8'));

const filePath = 'packages/classification-engine/src/config/category-config-schema.ts';
let content = fs.readFileSync(filePath, 'utf-8');

// Sort keys by length (longest first) to avoid partial replacements
const sortedKeys = Object.keys(mapping).sort((a, b) => b.length - a.length);

let count = 0;
sortedKeys.forEach(snakeCase => {
  const camelCase = mapping[snakeCase];

  // Match property declarations in Zod schemas (snake_case:)
  const regex = new RegExp(`\\b${snakeCase}\\s*:`, 'g');
  const matches = content.match(regex);

  if (matches) {
    content = content.replace(regex, `${camelCase}:`);
    count += matches.length;
    console.log(`✓ ${snakeCase} → ${camelCase} (${matches.length} occurrences)`);
  }
});

fs.writeFileSync(filePath, content, 'utf-8');
console.log(`\n✅ Fixed ${count} properties in category-config-schema.ts`);

